  "ProductName" = excluded."ProductName",
  "Category" = excluded."Category",
  "Subcategory" = excluded."Subcategory",
  "UnitCost" = excluded."UnitCost",
  "UnitPrice" = excluded."UnitPrice",
  "Weight_kg" = excluded."Weight_kg",
  "Supplier" = excluded."Supplier",
